parameters.jsCode:
const webhookBody = $input.first().json.body;

// Extract fields
const user_id = webhookBody.user_id || '';
const session_id = webhookBody.session_id || '';
const user_mssg = webhookBody.user_mssg || '';
const request_id = webhookBody.request_id || '';

// Parse conversation state
let incomingState = {};
try {
  const rawState = webhookBody.state || webhookBody.conversation_state;
  if (rawState) {
    incomingState = typeof rawState === 'string' ? JSON.parse(rawState) : rawState;
  }
} catch(e) {
  incomingState = {};
}

const topic = incomingState.topic || 'general';
const filesDiscussed = incomingState.files_discussed || [];
const context = incomingState.context || {};

// Build conversation context summary
let contextSummary = '';
if (topic !== 'general') {
  contextSummary = `\n\nCONVERSATION CONTEXT: Topic is ${topic}.`;
  if (filesDiscussed.length > 0) {
    contextSummary += ` Files discussed: ${filesDiscussed.join(', ')}.`;
  }
}

return [{
  json: {
    user_id,
    session_id,
    user_mssg,
    request_id,
    conversation_state: JSON.stringify(incomingState),
    context_summary: contextSummary
  }
}];

